  ('elementary-f29af906-moex-00174', 'elementary-f29af906', 'elementary-f29af906-moex-114-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '行政處分之撤銷與廢止有相異之處，下列敘述何者正確？', '["撤銷行政處分僅得由原處分機關為之", "行政處分廢止後，溯及既往失其效力，但受益人未履行負擔而受廢止者，自廢止後失其效力", "廢止行政處分僅得由上級機關為之", "違法行政處分經撤銷後，為維護公益，撤銷機關得另定失其效力之日期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "2422d4d20ab9", "answer_pdf_sha1": "1c183efc0748", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
